        </MudPickerToolbar>
        <MudPickerContent>
            <div id="@_mudPickerCalendarContentElementId" class="mud-picker-calendar-content @($"mud-picker-calendar-content-{MaxMonthColumns ?? DisplayMonths}")" @onmousedown:preventDefault="true">
                @{
                    int dayId = 0; 
                    var culture = GetCulture();
                    var calendar = culture.Calendar;
                    @if (_picker_month.HasValue && calendar.GetYear(_picker_month.Value) == 1 && calendar.GetMonth(_picker_month.Value) == 1)
                    {
                        dayId = -1;
                    }
                }
                @for (int displayMonth = 0; displayMonth < DisplayMonths; ++displayMonth)
                {
                    int tempMonth = displayMonth; //without local variable month names are wrong

                    <div class="mud-picker-calendar-container">
                        @if (tempMonth == 0 && CurrentView == OpenTo.Year)
                        {
                            <div id="pickerYears" class="mud-picker-year-container">
                                @for (int i = GetMinYear(); i <= GetMaxYear(); i++)
                                {
                                    var year = i;
                                    <div class="mud-picker-year" id="@(_componentId + year)" @onclick="@(async () => await OnYearClickedAsync(year))" @onclick:stopPropagation="true">
                                        <MudText Typo="@GetYearTypo(year)" Class="@GetYearClasses(year)">@year</MudText>
                                    </div>
                                }
                            </div>
                        }
                        else if (tempMonth == 0 && CurrentView == OpenTo.Month)
                        {
                            var calendarYear = GetCalendarYear(PickerMonth ?? DateTime.Today);

                            <div class="mud-picker-calendar-header">
                                <div class="mud-picker-calendar-header-switch">
                                    @if (!FixYear.HasValue)
                                    {
                                        <MudIconButton aria-label="@Localizer[LanguageResource.MudBaseDatePicker_PrevYear, $"({calendarYear - 1})"]" Icon="@PreviousIcon" OnClick="OnPreviousYearClick" Class="mud-flip-x-rtl" />
                                        <button type="button" class="mud-picker-slide-transition mud-picker-calendar-header-transition" @onclick="OnYearClick" @onclick:stopPropagation="true">
                                            <MudText Typo="Typo.body1" Align="Align.Center">@calendarYear</MudText>
                                        </button>
                                        <MudIconButton aria-label="@Localizer[LanguageResource.MudBaseDatePicker_NextYear, $"({calendarYear + 1})"]" Icon="@NextIcon" OnClick="OnNextYearClick" Class="mud-flip-x-rtl" />
                                    }
                                    else
                                    {
                                        <MudText Class="mud-picker-calendar-header-transition" Typo="Typo.body1" Align="Align.Center">@calendarYear</MudText>
                                    }
                                </div>
                            </div>
                            <div class="mud-picker-month-container">
                                @foreach (var month in GetAllMonths())
                                {
                                    <button type="button" aria-label="@GetMonthName(month)" disabled="@IsMonthDisabled(month)"
                                    class="mud-picker-month mud-button-root" @onclick="@(async () => await OnMonthSelectedAsync(month))" @onclick:stopPropagation="true">
                                        <MudText Typo="@GetMonthTypo(month)" Class="@GetMonthClasses(month)">@GetAbbreviatedMonthName(month)</MudText>
                                    </button>
                                }
                            </div>
                        }
                        else if (CurrentView == OpenTo.Date || tempMonth > 0)
                        {
                            <div class="@GetCalendarHeaderClasses(tempMonth)">
                                <div class="mud-picker-calendar-header-switch">
                                    @if (!FixMonth.HasValue)
                                    {
                                        <MudIconButton aria-label="@Localizer[LanguageResource.MudBaseDatePicker_PrevMonth, $"({GetMonthName((tempMonth - 1) % 12)})"]" Class="mud-picker-nav-button-prev mud-flip-x-rtl" Icon="@PreviousIcon" OnClick="@OnPreviousMonthClick" />
                                        <button type="button" class="mud-picker-slide-transition mud-picker-calendar-header-transition mud-button-month" @onclick="(() => OnMonthClicked(tempMonth))" @onclick:stopPropagation="true">
                                            <MudText Typo="Typo.body1" Align="Align.Center">@GetMonthName(tempMonth)</MudText>
                                        </button>
                                        <MudIconButton aria-label="@Localizer[LanguageResource.MudBaseDatePicker_NextMonth, $"({GetMonthName((tempMonth + 1) % 12)})"]" Class="mud-picker-nav-button-next mud-flip-x-rtl" Icon="@NextIcon" OnClick="@OnNextMonthClick" />
                                    }
                                    else
                                    {
                                        <MudText Class="mud-picker-calendar-header-transition" Typo="Typo.body1" Align="Align.Center">@GetMonthName(tempMonth)</MudText>
                                    }
                                </div>
                                <div class="mud-picker-calendar-header-day">
                                    @if (ShowWeekNumbers)
                                    {
                                        <div class="mud-picker-calendar-week">
                                            <MudText Typo="Typo.caption" Class="mud-picker-calendar-week-text"></MudText>
                                        </div>
                                    }
                                    @foreach (var dayName in GetAbbreviatedDayNames())
                                    {
                                        <MudText Typo="Typo.caption" Class="mud-day-label">@dayName</MudText>
                                    }
                                </div>
                            </div>
                            <div class="mud-picker-calendar-transition mud-picker-slide-transition">
                                <div class="mud-picker-calendar">
                                    @for (int week = 0; week < 6; week++)
                                    {
                                        int tempWeek = week;
                                        var firstMonthFirstYear = _picker_month.HasValue && calendar.GetYear(_picker_month.Value) == 1 && calendar.GetMonth(_picker_month.Value) == 1;

                                        @if (ShowWeekNumbers)
                                        {
                                            <div class="mud-picker-calendar-week">
                                                <MudText class="mud-picker-calendar-week-text" Typo="Typo.caption">@GetWeekNumber(tempMonth, tempWeek)</MudText>
                                            </div>
                                        }
                                        var wasMaxValue = false;
                                        @foreach (var day in GetWeek(tempMonth, tempWeek))
                                        {
                                            var tempId = ++dayId;

                                            @if ((tempId != 0 || !firstMonthFirstYear) && !wasMaxValue)
                                            {
                                                var selectedDay = !firstMonthFirstYear ? day : day.AddDays(-1);
                                                <button @key="@(!firstMonthFirstYear ? selectedDay : tempId)" type="button" style="--day-id: @(!firstMonthFirstYear ? tempId : tempId + 1);"
                                                        class="mud-button-root mud-icon-button mud-ripple mud-ripple-icon mud-picker-calendar-day @(!firstMonthFirstYear || day.Day == _picker_month!.Value.Day ? GetDayClasses(tempMonth, day) : GetDayClasses(tempMonth, selectedDay))"
                                                        @onclick="@(async () => { var d = selectedDay; await OnDayClickedAsync(d); })"
                                                        @onclick:stopPropagation="true"
                                                        onpointerover="@(async () => await HandleMouseoverOnPickerCalendarDayButton(!firstMonthFirstYear ? tempId : tempId + 1))"
                                                        disabled="@IsDayDisabled(selectedDay)">
                                                    <p class="mud-typography mud-typography-body2 mud-inherit-text">@GetCalendarDayOfMonth(selectedDay)</p>
                                                </button>
                                            }
                                            else
                                            {
                                                <button @key="0" type="button" disabled style="--day-id: 1;"
                                                        class="mud-button-root mud-icon-button mud-ripple mud-ripple-icon mud-picker-calendar-day mud-day">
                                                    <p class="mud-typography mud-typography-body2 mud-inherit-text"></p>
                                                </button>
                                            }
                                            wasMaxValue = day == calendar.MaxSupportedDateTime;
                                        }
                                    }
                                </div>
                            </div>
                        }
                    </div>
                }
            </div>
        </MudPickerContent>
    </CascadingValue>;
}

﻿using System.Globalization;
using Microsoft.AspNetCore.Components;
using MudBlazor.Extensions;
using MudBlazor.State;
using MudBlazor.Utilities;

namespace MudBlazor
{
    /// <summary>
    /// Represents a base class for designing date picker components.
    /// </summary>
    public abstract partial class MudBaseDatePicker : MudPicker<DateTime?>
    {
        private readonly string _mudPickerCalendarContentElementId;
        private readonly ParameterState<string?> _dateFormatState;

        protected MudBaseDatePicker()
        {
            _mudPickerCalendarContentElementId = Identifier.Create();
            Culture = CultureInfo.CurrentCulture;

            using var registerScope = CreateRegisterScope();
            _dateFormatState = registerScope.RegisterParameter<string?>(nameof(DateFormat))
                .WithParameter(() => DateFormat)
                .WithChangeHandler(DateFormatChangedAsync);
        }

        [Inject]
        protected IScrollManager ScrollManager { get; set; } = null!;

        [Inject]
        private IJsApiService JsApiService { get; set; } = null!;

        [Inject]
        protected TimeProvider TimeProvider { get; set; } = null!;

        /// <summary>
        /// The maximum selectable date.
        /// </summary>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Validation)]
        public DateTime? MaxDate { get; set; }

        /// <summary>
        /// The minimum selectable date.
        /// </summary>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Validation)]
        public DateTime? MinDate { get; set; }

        /// <summary>
        /// The initial view to display.
        /// </summary>
        /// <remarks>
        /// Defaults to <see cref="OpenTo.Date"/>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.PickerBehavior)]
        public OpenTo OpenTo { get; set; } = OpenTo.Date;

        /// <summary>
        /// The format for selected dates.
        /// </summary>
        [Parameter, ParameterState]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public string? DateFormat { get; set; }

        /// <summary>
        /// Occurs when the <see cref="DateFormat"/> has changed.
        /// </summary>
        protected virtual Task DateFormatChangedAsync(string? newFormat)
        {
            return Task.CompletedTask;
        }

        private Task DateFormatChangedAsync(ParameterChangedEventArgs<string?> args) => DateFormatChangedAsync(args.Value);

        /// <summary>
        /// The day representing the first day of the week.
        /// </summary>
        /// <remarks>
        /// Defaults to the current culture's <c>DateTimeFormat.FirstDayOfWeek</c>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.PickerBehavior)]
        public DayOfWeek? FirstDayOfWeek { get; set; }

        /// <summary>
        /// The current month shown in the date picker.
        /// </summary>
        /// <remarks>
        /// Defaults to the current month.<br />
        /// When bound via <c>@bind-PickerMonth</c>, controls the initial month displayed.  This value is always the first day of a month.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.PickerBehavior)]
        public DateTime? PickerMonth
        {
            get => _picker_month;
            set
            {
                if (value == _picker_month)
                    return;
                _picker_month = value;
                InvokeAsync(StateHasChanged);
                PickerMonthChanged.InvokeAsync(value);
            }
        }

        private DateTime? _picker_month;

        /// <summary>
        /// Represents the currently selected date
        /// </summary>
        /// <remarks>
        /// This date is highlighted in the UI
        /// </remarks>
        protected internal DateTime? HighlightedDate { get; set; }

        /// <summary>
        /// Occurs when <see cref="PickerMonth"/> has changed.
        /// </summary>
        [Parameter]
        public EventCallback<DateTime?> PickerMonthChanged { get; set; }

        /// <summary>
        /// The delay, in milliseconds, before closing the picker after a value is selected.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>100</c>.<br />
        /// This delay helps the user see that a date has been selected before the popover disappears.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.PickerBehavior)]
        public int ClosingDelay { get; set; } = 100;

        /// <summary>
        /// The number of months to display in the calendar.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>1</c>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.PickerBehavior)]
        public int DisplayMonths { get; set; } = 1;

        /// <summary>
        /// The maximum number of months allowed in one row.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>null</c>.<br />
        /// When <c>null</c>, the <see cref="DisplayMonths"/> is used.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.PickerAppearance)]
        public int? MaxMonthColumns { get; set; }

        /// <summary>
        /// The start month when opening the picker.
        /// </summary>
        [Parameter]
        [Category(CategoryTypes.FormComponent.PickerBehavior)]
        public DateTime? StartMonth { get; set; }

        /// <summary>
        /// Shows week numbers at the start of each week.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>false</c>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.PickerBehavior)]
        public bool ShowWeekNumbers { get; set; }

        /// <summary>
        /// The format of the selected date in the title.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>ddd, dd MMM</c>.<br />
        /// Supported date formats can be found here: <see href="https://learn.microsoft.com/dotnet/standard/base-types/standard-date-and-time-format-strings"/>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.PickerBehavior)]
        public string TitleDateFormat { get; set; } = "ddd, dd MMM";

        /// <summary>
        /// Closes this picker when a value is selected.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>false</c>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.PickerBehavior)]
        public bool AutoClose { get; set; }

        /// <summary>
        /// The function used to disable one or more dates.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>null</c>.<br />
        /// When set, a date will be disabled if the function returns <c>true</c>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Validation)]
        public Func<DateTime, bool> IsDateDisabledFunc { get; set; } = _ => false;

        /// <summary>
        /// The function which returns CSS classes for a date.
        /// </summary>
        /// <remarks>
        /// Multiple classes must be separated by spaces.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Appearance)]
        public Func<DateTime, string>? AdditionalDateClassesFunc { get; set; }

        /// <summary>
        /// The icon for the button that navigates to the previous month or year.
        /// </summary>
        /// <remarks>
        /// Defaults to <see cref="Icons.Material.Filled.ChevronLeft"/>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.PickerAppearance)]
        public string PreviousIcon { get; set; } = Icons.Material.Filled.ChevronLeft;

        /// <summary>
        /// The icon for the button which navigates to the next month or year.
        /// </summary>
        /// <remarks>
        /// Defaults to <see cref="Icons.Material.Filled.ChevronRight"/>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.PickerAppearance)]
        public string NextIcon { get; set; } = Icons.Material.Filled.ChevronRight;

        /// <summary>
        /// The year to use, which cannot be changed.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>null</c>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.PickerBehavior)]
        public int? FixYear { get; set; }

        /// <summary>
        /// The month to use, which cannot be changed.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>null</c>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.PickerBehavior)]
        public int? FixMonth { get; set; }

        /// <summary>
        /// The day to use, which cannot be changed.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>null</c>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.PickerBehavior)]
        public int? FixDay { get; set; }

        protected OpenTo CurrentView;

        protected override async Task OnPickerOpenedAsync()
        {
            await base.OnPickerOpenedAsync();
            if (Editable && Text != null)
            {
                var dateTime = ConvertGet(Text);
                if (dateTime.HasValue)
                {
                    var culture = GetCulture();
                    var calendar = culture.Calendar;
                    PickerMonth = new DateTime(calendar.GetYear(dateTime.Value), calendar.GetMonth(dateTime.Value), 1, calendar);
                }
            }
            if (OpenTo == OpenTo.Date && FixDay.HasValue && FixMonth.HasValue)
            {
                OpenTo = OpenTo.Year;
            }
            if (OpenTo == OpenTo.Date && FixDay.HasValue)
            {
                OpenTo = OpenTo.Month;
            }
            CurrentView = OpenTo;
            if (CurrentView == OpenTo.Year)
                _scrollToYearAfterRender = true;
        }

        /// <summary>
        /// Get the first of the month to display
        /// </summary>
        protected DateTime GetMonthStart(int month)
        {
            var culture = GetCulture();
            var calendar = culture.Calendar;

            // Handle explicit min boundary
            if (_picker_month is { Year: 1, Month: 1 })
            {
                return calendar.MinSupportedDateTime;
            }

            var baseDate = _picker_month ?? DateTime.Today.StartOfMonth(culture);

            var year = FixYear ?? calendar.GetYear(baseDate);
            var startMonth = FixMonth ?? calendar.GetMonth(baseDate);

            var monthStart = new DateTime(year, startMonth, 1, 0, 0, 0, 0, calendar, DateTimeKind.Utc);

            // Handle explicit max boundary
            if (_picker_month.HasValue &&
                calendar.GetYear(_picker_month.Value) == 9999 &&
                calendar.GetMonth(_picker_month.Value) ==
                calendar.GetMonthsInYear(9999) &&
                month >= 1)
            {
                return calendar.MaxSupportedDateTime;
            }

            return calendar.AddMonths(monthStart, month);
        }

        /// <summary>
        /// Get the last of the month to display
        /// </summary>
        protected DateTime GetMonthEnd(int month)
        {
            var culture = GetCulture();
            var calendar = culture.Calendar;
            var monthStartDate = _picker_month ?? DateTime.Today.StartOfMonth(culture);
            return calendar.AddMonths(monthStartDate, month).EndOfMonth(culture);
        }

        protected DayOfWeek GetFirstDayOfWeek()
        {
            if (FirstDayOfWeek.HasValue)
                return FirstDayOfWeek.Value;
            return GetCulture().DateTimeFormat.FirstDayOfWeek;
        }

        /// <summary>
        /// Gets the n-th week of the currently displayed month.
        /// </summary>
        /// <param name="month">offset from _picker_month</param>
        /// <param name="index">between 0 and 4</param>
        protected IEnumerable<DateTime> GetWeek(int month, int index)
        {
            if (index is < 0 or > 5)
            {
                throw new ArgumentException("Index must be between 0 and 5");
            }
            var culture = GetCulture();
            var calendar = culture.Calendar;
            var monthFirst = GetMonthStart(month);
            if ((calendar.MaxSupportedDateTime - monthFirst).Days >= index * 7)
            {
                var weekFirst = monthFirst.AddDays(index * 7).StartOfWeek(GetFirstDayOfWeek(), culture);
                for (var i = 0; i < 7; i++)
                {
                    if ((calendar.MaxSupportedDateTime - weekFirst).Days >= i)
                        yield return weekFirst.AddDays(i);
                    else
                        yield return calendar.MaxSupportedDateTime;
                }
            }
        }

        private string GetWeekNumber(int month, int index)
        {
            if (index is < 0 or > 5)
            {
                throw new ArgumentException("Index must be between 0 and 5");
            }

            var culture = GetCulture();
            var calendar = culture.Calendar;
            var monthFirst = GetMonthStart(month);
            var weekFirst = monthFirst.AddDays(index * 7).StartOfWeek(GetFirstDayOfWeek(), culture);
            //january 1st
            if (monthFirst.Month == 1 && index == 0)
            {
                weekFirst = monthFirst;
            }

            if (weekFirst.Month != monthFirst.Month && weekFirst.AddDays(6).Month != monthFirst.Month)
            {
                return string.Empty;
            }

            return calendar.GetWeekOfYear(weekFirst, culture.DateTimeFormat.CalendarWeekRule, FirstDayOfWeek ?? culture.DateTimeFormat.FirstDayOfWeek).ToString();
        }

        protected virtual OpenTo? GetNextView()
        {
            OpenTo? nextView = CurrentView switch
            {
                OpenTo.Year => GetNextViewFromYear(),
                OpenTo.Month => !FixDay.HasValue ? OpenTo.Date : null,
                _ => null,
            };
            return nextView;
        }

        protected virtual OpenTo? GetPreviousView()
        {
            OpenTo? previousView = CurrentView switch
            {
                OpenTo.Date => GetPreviousViewFromDate(),
                OpenTo.Month => !FixYear.HasValue ? OpenTo.Year : null,
                _ => null,
            };
            return previousView;
        }

        private OpenTo? GetNextViewFromYear()
        {
            if (!FixMonth.HasValue)
            {
                return OpenTo.Month;
            }

            if (!FixDay.HasValue)
            {
                return OpenTo.Date;
            }

            return null;
        }

        private OpenTo? GetPreviousViewFromDate()
        {
            if (!FixMonth.HasValue)
            {
                return OpenTo.Month;
            }

            if (!FixYear.HasValue)
            {
                return OpenTo.Year;
            }

            return null;
        }

        protected virtual async Task SubmitAndCloseAsync()
        {
            if (PickerActions == null)
            {
                await SubmitAsync();

                if (PickerVariant != PickerVariant.Static)
                {
                    await Task.Delay(TimeSpan.FromMilliseconds(ClosingDelay), TimeProvider);
                    await CloseAsync(false);
                }
            }
        }

        protected virtual bool IsDayDisabled(DateTime date)
        {
            return date < MinDate ||
                   date > MaxDate ||
                   IsDateDisabledFunc(date);
        }

        protected abstract string GetDayClasses(int month, DateTime day);

        /// <summary>
        /// User clicked on a day
        /// </summary>
        protected abstract Task OnDayClickedAsync(DateTime dateTime);

        /// <summary>
        /// user clicked on a month
        /// </summary>
        /// <param name="month"></param>
        protected virtual Task OnMonthSelectedAsync(DateTime month)
        {
            PickerMonth = month;
            var nextView = GetNextView();
            if (nextView != null)
            {
                CurrentView = (OpenTo)nextView;
            }

            return Task.CompletedTask;
        }

        /// <summary>
        /// user clicked on a year
        /// </summary>
        /// <param name="year"></param>
        protected virtual Task OnYearClickedAsync(int year)
        {
            var current = GetMonthStart(0);
            PickerMonth = new DateTime(year, current.Month, 1, GetCulture().Calendar);
            var nextView = GetNextView();
            if (nextView != null)
            {
                CurrentView = (OpenTo)nextView;
            }

            return Task.CompletedTask;
        }

        /// <summary>
        /// user clicked on a month
        /// </summary>
        protected virtual void OnMonthClicked(int month)
        {
            CurrentView = OpenTo.Month;
            _picker_month = _picker_month?.AddMonths(month);
            StateHasChanged();
        }

        /// <summary>
        /// Check if month is disabled
        /// </summary>
        /// <param name="month">Month given with first day of the month</param>
        /// <returns>True if month should be disabled, false otherwise</returns>
        private bool IsMonthDisabled(DateTime month)
        {
            var culture = GetCulture();
            var calendar = culture.Calendar;
            if (!FixDay.HasValue)
            {
                return month.EndOfMonth(culture) < MinDate || month > MaxDate;
            }
            if (calendar.GetDaysInMonth(calendar.GetYear(month), calendar.GetMonth(month)) < FixDay!.Value)
            {
                return true;
            }
            var day = new DateTime(month.Year, month.Month, FixDay!.Value);
            return day < MinDate || day > MaxDate || IsDateDisabledFunc(day);
        }

        /// <summary>
        /// return Mo, Tu, We, Th, Fr, Sa, Su in the right culture
        /// </summary>
        protected IEnumerable<string> GetAbbreviatedDayNames()
        {
            var dayNamesNormal = GetCulture().DateTimeFormat.AbbreviatedDayNames;
            var dayNamesShifted = Shift(dayNamesNormal, (int)GetFirstDayOfWeek());
            return dayNamesShifted;
        }

        /// <summary>
        /// Shift array and cycle around from the end
        /// </summary>
        private static T[] Shift<T>(T[] array, int positions)
        {
            var copy = new T[array.Length];
            Array.Copy(array, 0, copy, array.Length - positions, positions);
            Array.Copy(array, positions, copy, 0, array.Length - positions);
            return copy;
        }

        protected string GetMonthName(int month)
        {
            return GetMonthStart(month).ToString(GetCulture().DateTimeFormat.YearMonthPattern, GetCulture());
        }

        protected abstract string GetTitleDateString();

        protected string FormatTitleDate(DateTime? date)
        {
            return date?.ToString(TitleDateFormat ?? "ddd, dd MMM", GetCulture()) ?? "";
        }

        protected string GetFormattedYearString()
        {
            var selectedYear = HighlightedDate ?? GetMonthStart(0);

            return GetCalendarYear(selectedYear).ToString();
        }

        private void OnPreviousMonthClick()
        {
            var culture = GetCulture();
            var calendar = culture.Calendar;
            // It is impossible to go further into the past after reaching DateTime.MinValue
            if (PickerMonth.HasValue && calendar.GetYear(PickerMonth.Value) == DateTime.MinValue.Year && calendar.GetMonth(PickerMonth.Value) == DateTime.MinValue.Month)
            {
                return;
            }
            PickerMonth = GetMonthStart(0).AddDays(-1).StartOfMonth(GetCulture());
        }

        private void OnNextMonthClick()
        {
            var culture = GetCulture();
            var calendar = culture.Calendar;
            // It is impossible to go further into the future after reaching DateTime.MaxValue
            if (PickerMonth.HasValue && calendar.GetYear(PickerMonth.Value) == DateTime.MaxValue.Year
                && calendar.GetMonth(PickerMonth.Value) == DateTime.MaxValue.Month)
            {
                return;
            }
            PickerMonth = GetMonthEnd(0).AddDays(1);
        }

        private void OnPreviousYearClick()
        {
            var culture = GetCulture();
            var calendar = culture.Calendar;
            // It is impossible to go further into the past after reaching DateTime.MinValue
            if (PickerMonth.HasValue && calendar.GetYear(PickerMonth.Value) == DateTime.MinValue.Year)
            {
                return;
            }
            PickerMonth = GetMonthStart(0).AddYears(-1);
        }

        private void OnNextYearClick()
        {
            var culture = GetCulture();
            var calendar = culture.Calendar;
            // It is impossible to go further into the future after reaching DateTime.MaxValue
            if (PickerMonth.HasValue && calendar.GetYear(PickerMonth.Value) == DateTime.MaxValue.Year)
            {
                return;
            }
            PickerMonth = GetMonthStart(0).AddYears(1);
        }

        private void OnYearClick()
        {
            if (!FixYear.HasValue)
            {
                CurrentView = OpenTo.Year;
                StateHasChanged();
                _scrollToYearAfterRender = true;
            }
        }

        private void GoToSelectedYear()
        {
            PickerMonth = HighlightedDate;
            OnYearClick();
        }

        /// <summary>
        /// We need a random id for the year items in the year list so we can scroll to the item safely in every DatePicker.
        /// </summary>
        private readonly string _componentId = Identifier.Create();

        /// <summary>
        /// Is set to true to scroll to the actual year after the next render
        /// </summary>
        protected bool _scrollToYearAfterRender = false;

        /// <summary>
        /// Scrolls to the current year.
        /// </summary>
        public async Task ScrollToYearAsync(DateTime? date = null)
        {
            var culture = GetCulture();
            var calendar = culture.Calendar;
            _scrollToYearAfterRender = false;
            var dateTime = date ?? GetMonthStart(0);
            var id = $"{_componentId}{calendar.GetYear(dateTime)}";
            await ScrollManager.ScrollToYearAsync(id);
            StateHasChanged();
        }

        protected int GetMinYear()
        {
            var culture = GetCulture();
            var calendar = culture.Calendar;
            if (MinDate.HasValue)
                return calendar.GetYear(MinDate.Value);
            return calendar.GetYear(DateTime.Today) - 100;
        }

        protected int GetMaxYear()
        {
            var culture = GetCulture();
            var calendar = culture.Calendar;
            if (MaxDate.HasValue)
                return calendar.GetYear(MaxDate.Value);
            return calendar.GetYear(DateTime.Today) + 100;
        }

        private string? GetYearClasses(int year)
        {
            var selectedYear = HighlightedDate ?? GetMonthStart(0);
            var culture = GetCulture();
            var calendar = culture.Calendar;
            if (year == calendar.GetYear(selectedYear))
                return $"mud-picker-year-selected mud-{Color.ToStringFast(true)}-text";
            return null;
        }

        private string GetCalendarHeaderClasses(int month)
        {
            return new CssBuilder("mud-picker-calendar-header")
                .AddClass($"mud-picker-calendar-header-{month + 1}")
                .AddClass($"mud-picker-calendar-header-last", month == DisplayMonths - 1)
                .Build();
        }

        private Typo GetYearTypo(int year)
        {
            var selectedYear = HighlightedDate ?? GetMonthStart(0);
            var culture = GetCulture();
            var calendar = culture.Calendar;
            if (year == calendar.GetYear(selectedYear))
                return Typo.h5;

            return Typo.subtitle1;
        }

        private void OnFormattedDateClick()
        {
            // todo: raise an event the user can handle
        }

        private IEnumerable<DateTime> GetAllMonths()
        {
            var current = GetMonthStart(0);
            var culture = GetCulture();
            var calendar = culture.Calendar;
            var calendarYear = calendar.GetYear(current);
            var firstOfCalendarYear = calendar.ToDateTime(calendarYear, 1, 1, 0, 0, 0, 0);
            for (var i = 0; i < calendar.GetMonthsInYear(calendarYear); i++)
                yield return calendar.AddMonths(firstOfCalendarYear, i);
        }

        private string GetAbbreviatedMonthName(DateTime month)
        {
            var culture = GetCulture();
            var calendar = culture.Calendar;
            var calendarMonth = calendar.GetMonth(month);
            return GetCulture().DateTimeFormat.AbbreviatedMonthNames[calendarMonth - 1];
        }

        private string GetMonthName(DateTime month)
        {
            var culture = GetCulture();
            var calendar = culture.Calendar;
            var calendarMonth = calendar.GetMonth(month);
            return GetCulture().DateTimeFormat.MonthNames[calendarMonth - 1];
        }

        private string? GetMonthClasses(DateTime month)
        {
            var selectedMonth = HighlightedDate ?? GetMonthStart(0);
            var culture = GetCulture();
            var calendar = culture.Calendar;
            if (calendar.GetYear(month) != calendar.GetYear(selectedMonth))
                return null;

            if (calendar.GetMonth(month) == calendar.GetMonth(selectedMonth) && !IsMonthDisabled(selectedMonth))
                return $"mud-picker-month-selected mud-{Color.ToStringFast(true)}-text";

            return null;
        }

        private Typo GetMonthTypo(DateTime month)
        {
            var selectedMonth = HighlightedDate ?? GetMonthStart(0);
            var culture = GetCulture();
            var calendar = culture.Calendar;
            if (calendar.GetYear(month) != calendar.GetYear(selectedMonth))
                return Typo.subtitle1;

            if (calendar.GetMonth(month) == calendar.GetMonth(selectedMonth))
                return Typo.h5;

            return Typo.subtitle1;
        }
        protected override void OnInitialized()
        {
            base.OnInitialized();
            AdornmentAriaLabel ??= Localizer[Resources.LanguageResource.MudBaseDatePicker_Open];
            CurrentView = OpenTo;

            if (HighlightedDate is not null)
            {
                return;
            }

            var culture = GetCulture();
            var calendar = culture.Calendar;
            var today = TimeProvider.GetLocalNow().Date;

            var year = FixYear ?? calendar.GetYear(today);
            var month = FixMonth ?? (year == calendar.GetYear(today) ? calendar.GetMonth(today) : 1);
            var day = FixDay ?? 1;

            if (DateTime.TryParseExact($"{year}-{month}-{day}", "yyyy-M-d", GetCulture(), DateTimeStyles.None, out var date))
            {
                HighlightedDate = date;
            }
        }

        protected override async Task OnAfterRenderAsync(bool firstRender)
        {
            await base.OnAfterRenderAsync(firstRender);

            if (firstRender)
            {
                _picker_month ??= GetCalendarStartOfMonth();
            }

            if (firstRender && CurrentView == OpenTo.Year)
            {
                ScrollToYearAsync().CatchAndLog();
                return;
            }

            if (_scrollToYearAfterRender)
                ScrollToYearAsync().CatchAndLog();
        }

        /// <inheritdoc />
        protected override IConverter<DateTime?, string?> GetDefaultConverter()
        {
            return new DefaultConverter<DateTime?>
            {
                Culture = GetCulture,
                Format = GetFormat
            };
        }

        protected override string GetFormat()
        {
            if (!string.IsNullOrEmpty(_dateFormatState.Value))
            {
                return _dateFormatState.Value;
            }

            var culture = GetCulture();
            if (!string.IsNullOrEmpty(culture.DateTimeFormat.ShortDatePattern))
            {
                // In some cases, a custom culture may set the ShortDatePattern to an empty string.
                // This could result in an invalid or unintended date format, but if it's not empty, return the custom ShortDatePattern.
                return culture.DateTimeFormat.ShortDatePattern;
            }

            return CultureInfo.CurrentCulture.DateTimeFormat.ShortDatePattern;
        }

        protected abstract DateTime GetCalendarStartOfMonth();

        private int GetCalendarDayOfMonth(DateTime date)
        {
            var culture = GetCulture();
            var calendar = culture.Calendar;
            return calendar.GetDayOfMonth(date);
        }

        /// <summary>
        /// Converts gregorian date into whatever year it is in the provided culture
        /// </summary>
        /// <param name="yearDate">Gregorian Date</param>
        /// <returns>Year according to culture</returns>
        protected abstract int GetCalendarYear(DateTime yearDate);

        private ValueTask HandleMouseoverOnPickerCalendarDayButton(int tempId)
        {
            return JsApiService.UpdateStyleProperty(_mudPickerCalendarContentElementId, "--selected-day", tempId);
        }
    }
}

﻿using Microsoft.AspNetCore.Components;
using MudBlazor.Extensions;
using MudBlazor.Resources;
using MudBlazor.State;
using MudBlazor.Utilities;

namespace MudBlazor
{
    /// <summary>
    /// Represents a picker for a range of dates.
    /// </summary>
    /// <seealso cref="MudDatePicker"/>
    public partial class MudDateRangePicker : MudBaseDatePicker
    {
        private readonly ParameterState<bool> _allowDisabledDatesInCountState;
        private DateTime? _firstDate, _secondDate, _minValidDate, _maxValidDate;
        private DateRange? _dateRange;
        private Range<string>? _rangeText;

        /// <summary>
        /// Creates a new instance.
        /// </summary>
        public MudDateRangePicker()
        {
            using var registerScope = CreateRegisterScope();
            _allowDisabledDatesInCountState = registerScope.RegisterParameter<bool>(nameof(AllowDisabledDatesInCount))
                .WithParameter(() => AllowDisabledDatesInCount)
                .WithChangeHandler(RecalculateValidDays);

            DisplayMonths = 2;
        }

        /// <summary>
        /// The maximum number of selectable days.
        /// </summary>
        /// <remarks>
        /// Inclusive of the selected date.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public int? MaxDays { get; set; }

        /// <summary>
        /// The minimum number of selectable days.
        /// </summary>
        /// <remarks>
        /// Inclusive of the selected date.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public int? MinDays { get; set; }

        /// <summary>
        /// Include disabled dates within the valid min/max days range.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>true</c>. Disabled days will be included in the min/max count. 
        /// This parameter will take effect when <see cref="MinDays"/> or <see cref="MaxDays"/> is set.
        /// </remarks>
        [Parameter, ParameterState]
        [Category(CategoryTypes.FormComponent.Validation)]
        public bool AllowDisabledDatesInCount { get; set; } = true;

        /// <summary>
        /// The text displayed in the start input if no date is specified.
        /// </summary>
        /// <remarks>
        /// This property is typically used to give the user a hint as to what kind of input is expected.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public string? PlaceholderStart { get; set; }

        /// <summary>
        /// The text displayed in the end input if no date is specified.
        /// </summary>
        /// <remarks>
        /// This property is typically used to give the user a hint as to what kind of input is expected.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public string? PlaceholderEnd { get; set; }

        /// <summary>
        /// The accessible name for the starting input field.
        /// </summary>
        /// <remarks>
        /// Defaults to a localized "Start date" label when <c>null</c>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public string? StartInputAriaLabel { get; set; }

        /// <summary>
        /// The accessible name for the ending input field.
        /// </summary>
        /// <remarks>
        /// Defaults to a localized "End date" label when <c>null</c>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public string? EndInputAriaLabel { get; set; }

        private string StartInputAriaLabelString => StartInputAriaLabel ?? Localizer[LanguageResource.MudDateRangePicker_Start];

        private string EndInputAriaLabelString => EndInputAriaLabel ?? Localizer[LanguageResource.MudDateRangePicker_End];

        /// <summary>
        /// The icon displayed between start and end dates.
        /// </summary>
        /// <remarks>
        /// Defaults to <see cref="Icons.Material.Filled.ArrowRightAlt"/>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Appearance)]
        public string SeparatorIcon { get; set; } = Icons.Material.Filled.ArrowRightAlt;

        /// <summary>
        /// Occurs when <see cref="DateRange"/> has changed.
        /// </summary>
        [Parameter]
        public EventCallback<DateRange?> DateRangeChanged { get; set; }

        /// <summary>
        /// The currently selected date range.
        /// </summary>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Data)]
        public DateRange? DateRange
        {
            get => _dateRange;
            set => SetDateRangeAsync(value, true).CatchAndLog();
        }

        /// <summary>
        /// Enables capture for disabled dates within the selected date range.
        /// </summary>
        /// <remarks>
        /// By default, it will always ignore disabled dates. This parameter will take effect when <see cref="MudBaseDatePicker.IsDateDisabledFunc"/> is set.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Validation)]
        public bool AllowDisabledDatesInRange { get; set; } = false;

        protected async Task SetDateRangeAsync(DateRange? range, bool updateValue)
        {
            // Normalize the DateRange before exception is thrown
            range = NormalizeDateRange(range);

            if (_dateRange != range)
            {
                var doesRangeContainDisabledDates = !AllowDisabledDatesInRange && range is { Start: not null, End: not null } && Enumerable
                    .Range(0, int.MaxValue)
                    .Select(index => range.Start.Value.AddDays(index))
                    .TakeWhile(date => date <= range.End.Value)
                    .Any(date => IsDateDisabledFunc(date.Date));

                if (doesRangeContainDisabledDates)
                {
                    _rangeText = null;
                    await SetTextAsync(null, false);
                    return;
                }

                Touched = true;

                if (range?.Start is not null && StartMonth == null)
                    PickerMonth = new DateTime(GetCulture().Calendar.GetYear(range.Start.Value), GetCulture().Calendar.GetMonth(range.Start.Value), 1, GetCulture().Calendar);

                _dateRange = range;
                _value = range?.End;
                HighlightedDate = range?.Start;

                if (updateValue)
                {
                    ResetConverterErrors();
                    if (_dateRange == null || (_dateRange.Start == null && _dateRange.End == null))
                    {
                        _rangeText = null;
                        await SetTextAsync(null, false);
                    }
                    else
                    {
                        _rangeText = new Range<string>(
                            ConvertSet(_dateRange.Start),
                            ConvertSet(_dateRange.End));
                        await SetTextAsync(_dateRange.ToString(GetConverter()), false);
                    }
                }

                await DateRangeChanged.InvokeAsync(_dateRange);
                await BeginValidateAsync();
                FieldChanged(_value);
            }
        }

        private Range<string>? RangeText
        {
            get => _rangeText;
            set
            {
                if (_rangeText?.Equals(value) ?? (value == null))
                    return;

                Touched = true;
                _rangeText = value;
                SetDateRangeAsync(value is null ? null : ParseDateRangeValue(value.Start, value.End), false).CatchAndLog();
            }
        }

        private MudRangeInput<string> _rangeInput = null!;

        /// <summary>
        /// Focuses the start input.
        /// </summary>
        public ValueTask FocusStartAsync() => _rangeInput.FocusStartAsync();

        /// <summary>
        /// Selects the start input text.
        /// </summary>
        public ValueTask SelectStartAsync() => _rangeInput.SelectStartAsync();

        /// <summary>
        /// Selects a portion of the start input text.
        /// </summary>
        /// <param name="pos1">The index of the first character to select.</param>
        /// <param name="pos2">The index of the last character to select.</param>
        public ValueTask SelectRangeStartAsync(int pos1, int pos2) => _rangeInput.SelectRangeStartAsync(pos1, pos2);

        /// <summary>
        /// Focuses the end input.
        /// </summary>
        public ValueTask FocusEndAsync() => _rangeInput.FocusEndAsync();

        /// <summary>
        /// Selects the end input text.
        /// </summary>
        public ValueTask SelectEndAsync() => _rangeInput.SelectEndAsync();

        public override ValueTask BlurAsync() => _rangeInput.BlurAsync();

        /// <summary>
        /// Selects a portion of the end input text.
        /// </summary>
        /// <param name="pos1">The index of the first character to select.</param>
        /// <param name="pos2">The index of the last character to select.</param>
        public ValueTask SelectRangeEndAsync(int pos1, int pos2) => _rangeInput.SelectRangeEndAsync(pos1, pos2);

        protected override Task DateFormatChangedAsync(string? newFormat)
        {
            Touched = true;
            _rangeText = null;
            if (_dateRange?.Start != null || _dateRange?.End != null)
            {
                _rangeText = new Range<string>(
                    ConvertSet(_dateRange.Start),
                    ConvertSet(_dateRange.End));
            }

            return SetTextAsync(_dateRange?.ToString(GetConverter()), false);
        }

        protected override Task StringValueChangedAsync(string? value)
        {
            Touched = true;
            // Update the date range property (without updating back the Value property)
            return SetDateRangeAsync(ParseDateRangeValue(value), false);
        }

        protected override bool HasValue(DateTime? value) => value is not null;

        protected override bool IsDayDisabled(DateTime date)
        {
            if (_firstDate is null || _secondDate is not null)
            {
                return base.IsDayDisabled(date);
            }

            var selectedDate = _firstDate.Value;
            var validDateRange = GetValidDateRange(selectedDate);

            return base.IsDayDisabled(date) || IsDateOutOfRange(date, selectedDate, validDateRange);
        }

        private DateRange GetValidDateRange(DateTime selectedDate)
        {
            var start = MinDays switch
            {
                null => MinDate ?? DateTime.MinValue,
                _ when _allowDisabledDatesInCountState.Value => selectedDate.Date.AddDays(MinDays.Value - 1),
                _ => _minValidDate
            };

            var end = MaxDays switch
            {
                null => MaxDate ?? DateTime.MaxValue,
                _ when _allowDisabledDatesInCountState.Value => selectedDate.Date.AddDays(MaxDays.Value - 1),
                _ => _maxValidDate
            };

            return new DateRange(start, end);
        }

        private static bool IsDateOutOfRange(DateTime date, DateTime selectedDate, DateRange validRange)
        {
            var isNotSelectedDate = date < selectedDate || date > selectedDate;
            var isOutsideValidRange = date < validRange.Start || date > validRange.End;

            return isNotSelectedDate && isOutsideValidRange;
        }

        private DateTime GetMaxSelectableDate(DateTime startDate, int maxDays)
        {
            var validDayCount = 1;
            var lastValidDate = startDate;
            var maxDate = startDate.AddDays(1);

            while (validDayCount < maxDays)
            {
                if (!IsDateDisabledFunc(maxDate))
                {
                    validDayCount++;
                    lastValidDate = maxDate;
                }

                if (validDayCount == maxDays)
                    break;

                if (maxDate.Date > MaxDate.GetValueOrDefault(startDate.AddYears(50)).Date)
                    break;

                if (maxDate.Date == DateTime.MaxValue.Date)
                    break;

                maxDate = maxDate.AddDays(1);
            }

            return lastValidDate;
        }

        /// <summary>
        /// Recalculate the valid days in relation to the <see cref="MinDays"/> and <see cref="MaxDays"/> allowed
        /// </summary>
        public void RecalculateValidDays()
        {
            if (_firstDate is null) return;

            if (MinDays is not null)
                _minValidDate = GetMaxSelectableDate(_firstDate.Value, MinDays.Value);

            if (MaxDays is not null)
                _maxValidDate = GetMaxSelectableDate(_firstDate.Value, MaxDays.Value);

            StateHasChanged();
        }

        private DateRange? ParseDateRangeValue(string? value)
        {
            return DateRange.TryParse(value, GetConverter(), out var dateRange) ? dateRange : null;
        }

        private DateRange? ParseDateRangeValue(string? start, string? end)
        {
            return DateRange.TryParse(start, end, GetConverter(), out var dateRange) ? dateRange : null;
        }

        protected override Task OnPickerClosedAsync()
        {
            _firstDate = null;

            return base.OnPickerClosedAsync();
        }

        private bool CheckDateRange(DateTime day, Func<DateTime, DateTime, bool> compareStart, Func<DateTime, DateTime, bool> compareEnd)
        {
            return _firstDate is null
                && _dateRange is { Start: { } start, End: { } end }
                && compareStart(start.Date, day)
                && compareEnd(end.Date, day);
        }

        protected override string GetDayClasses(int month, DateTime day)
        {
            var b = new CssBuilder("mud-day");
            b.AddClass(AdditionalDateClassesFunc?.Invoke(day) ?? string.Empty);
            if (day < GetMonthStart(month) || day > GetMonthEnd(month))
            {
                return b.AddClass("mud-hidden").Build();
            }

            static bool isLessThan(DateTime date1, DateTime date2) => date1 < date2;
            static bool isGreaterThan(DateTime date1, DateTime date2) => date1 > date2;
            static bool isEqualTo(DateTime date1, DateTime date2) => date1 == date2;
            static bool isNotEqualTo(DateTime date1, DateTime date2) => date1 != date2;

            if ((_firstDate?.Date < day && _secondDate?.Date > day) || CheckDateRange(day, compareStart: isLessThan, compareEnd: isGreaterThan))
            {
                return b
                    .AddClass("mud-range")
                    .AddClass("mud-range-between")
                    .AddClass($"mud-current mud-{Color.ToStringFast(true)}-text mud-button-outlined mud-button-outlined-{Color.ToStringFast(true)}", day == DateTime.Today)
                    .Build();
            }

            if (_firstDate?.Date == day && _secondDate?.Date == day)
            {
                return b.AddClass("mud-selected")
                    .AddClass($"mud-theme-{Color.ToStringFast(true)}")
                    .Build();
            }

            if (_firstDate?.Date == day || CheckDateRange(day, compareStart: isEqualTo, compareEnd: isNotEqualTo))
            {
                return b.AddClass("mud-selected")
                    .AddClass("mud-range")
                    .AddClass("mud-range-start-selected")
                    .AddClass("mud-range-selection", _firstDate != null)
                    .AddClass($"mud-theme-{Color.ToStringFast(true)}")
                    .Build();
            }

            if ((_firstDate is { } && _secondDate?.Date == day) || CheckDateRange(day, compareStart: isNotEqualTo, compareEnd: isEqualTo))
            {
                return b.AddClass("mud-selected")
                    .AddClass("mud-range")
                    .AddClass("mud-range-end-selected")
                    .AddClass($"mud-theme-{Color.ToStringFast(true)}")
                    .Build();
            }

            if (CheckDateRange(day, compareStart: isEqualTo, compareEnd: isEqualTo))
            {
                return b.AddClass("mud-selected").AddClass($"mud-theme-{Color.ToStringFast(true)}").Build();
            }

            if (_firstDate?.Date < day)
            {
                return b.AddClass("mud-range", _secondDate is null && day != DateTime.Today)
                    .AddClass("mud-range-selection")
                    .AddClass($"mud-range-selection-{Color.ToStringFast(true)}", _firstDate is not null)
                    .AddClass($"mud-current mud-{Color.ToStringFast(true)}-text mud-button-outlined mud-button-outlined-{Color.ToStringFast(true)}", day == DateTime.Today)
                    .Build();
            }

            if (day == DateTime.Today)
            {
                return b.AddClass("mud-current")
                    .AddClass($"mud-button-outlined mud-button-outlined-{Color.ToStringFast(true)}")
                    .AddClass($"mud-{Color.ToStringFast(true)}-text")
                    .Build();
            }

            return b.Build();
        }

        protected override async Task OnDayClickedAsync(DateTime dateTime)
        {
            if (GetReadOnlyState())
                return;
            if (_firstDate == null || _secondDate != null)
            {
                _secondDate = null;
                _firstDate = dateTime;

                RecalculateValidDays();

                return;
            }
            if (_firstDate > dateTime)
            {
                _secondDate = _firstDate;
                _firstDate = dateTime;
            }
            else
            {
                _secondDate = dateTime;
            }
            if (PickerActions == null || AutoClose)
            {
                await SubmitAsync();

                if (PickerVariant != PickerVariant.Static)
                {
                    await Task.Delay(TimeSpan.FromMilliseconds(ClosingDelay), TimeProvider);
                    await CloseAsync(false);
                }
            }
        }

        protected override Task OnOpenedAsync()
        {
            _secondDate = null;
            return base.OnOpenedAsync();
        }

        protected internal override async Task SubmitAsync()
        {
            if (GetReadOnlyState())
                return;
            if (_firstDate == null || _secondDate == null)
                return;

            await SetDateRangeAsync(new DateRange(_firstDate, _secondDate), true);

            _firstDate = null;
            _secondDate = null;
        }

        protected override Task ResetValueAsync() => ClearAsync();

        public override async Task ClearAsync(bool close = true)
        {
            await SetDateRangeAsync(null, true);
            _firstDate = _secondDate = null;
            await base.ClearAsync(close);
        }

        protected override string GetTitleDateString()
        {
            if (_firstDate != null)
                return $"{FormatTitleDate(_firstDate)} - {FormatTitleDate(_secondDate)}";

            return DateRange?.Start != null
                ? $"{FormatTitleDate(DateRange.Start)} - {FormatTitleDate(DateRange.End)}"
                : "";
        }

        protected override DateTime GetCalendarStartOfMonth()
        {
            var date = StartMonth ?? DateRange?.Start ?? DateTime.Today;
            return date.StartOfMonth(GetCulture());
        }

        protected override async Task OnYearClickedAsync(int year)
        {
            await base.OnYearClickedAsync(year);

            if (DateRange?.Start is null && _firstDate is null)
            {
                HighlightedDate = PickerMonth;
            }
        }

        protected override int GetCalendarYear(DateTime yearDate)
        {
            var date = DateRange?.Start ?? DateTime.Today;
            var diff = GetCulture().Calendar.GetYear(date) - GetCulture().Calendar.GetYear(yearDate);
            var calenderYear = GetCulture().Calendar.GetYear(date);
            return calenderYear - diff;
        }

        /// <summary>
        /// Normalize a date by treating DateTime.MinValue as null
        /// This prevents an ArgumentOutOfRangeException from happening when performing date arithmetic
        /// </summary>
        /// <param name="date">The date to normalize</param>
        /// <returns>Normalized date or null</returns>
        private static DateTime? NormalizeDate(DateTime? date)
        {
            if (date is null)
                return null;

            // Treat DateTime.MinValue as null
            if (date.Value == DateTime.MinValue)
                return null;

            return date;
        }

        /// <summary>
        /// Normalize a date range by checking the start date and end date for DateTime.MinValue
        /// This prevents an ArgumentOutOfRangeException from happening when performing date arithmetic
        /// </summary>
        /// <see cref="NormalizeDate"/>
        /// <param name="range">The date range to normalize</param>
        /// <returns>Normalized date range or null</returns>
        private static DateRange? NormalizeDateRange(DateRange? range)
        {
            if (range is null)
                return null;

            var start = NormalizeDate(range.Start);
            var end = NormalizeDate(range.End);

            return new DateRange(start, end);
        }

    }
}

